import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from 'react-query';
import { ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

// Auth Context
import { AuthProvider } from './contexts/AuthContext';
import { SocketProvider } from './contexts/SocketContext';

// Layout Components
import Layout from './components/Layout';
import PrivateRoute from './components/PrivateRoute';
import AdminRoute from './components/AdminRoute';

// Public Pages
import Login from './pages/Login';
import Register from './pages/Register';
import Terms from './pages/Terms';

// Customer Pages
import CustomerDashboard from './pages/customer/Dashboard';
import CustomerTransactions from './pages/customer/Transactions';
import CustomerReturns from './pages/customer/Returns';
import CustomerMessages from './pages/customer/Messages';
import CustomerProfile from './pages/customer/Profile';
import CreateReturn from './pages/customer/CreateReturn';
import RateTransaction from './pages/customer/RateTransaction';

// Admin Pages
import AdminDashboard from './pages/admin/Dashboard';
import AdminSensors from './pages/admin/Sensors';
import AdminTransactions from './pages/admin/Transactions';
import AdminReturns from './pages/admin/Returns';
import AdminRatings from './pages/admin/Ratings';
import AdminMessages from './pages/admin/Messages';
import AdminReports from './pages/admin/Reports';
import AdminUsers from './pages/admin/Users';

const queryClient = new QueryClient();

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <AuthProvider>
        <SocketProvider>
          <Router>
            <Routes>
              {/* Public Routes */}
              <Route path="/login" element={<Login />} />
              <Route path="/register" element={<Register />} />
              <Route path="/terms" element={<Terms />} />
              
              {/* Customer Routes */}
              <Route path="/customer" element={
                <PrivateRoute>
                  <Layout />
                </PrivateRoute>
              }>
                <Route index element={<Navigate to="/customer/dashboard" />} />
                <Route path="dashboard" element={<CustomerDashboard />} />
                <Route path="transactions" element={<CustomerTransactions />} />
                <Route path="returns" element={<CustomerReturns />} />
                <Route path="returns/create" element={<CreateReturn />} />
                <Route path="rate/:transactionId" element={<RateTransaction />} />
                <Route path="messages" element={<CustomerMessages />} />
                <Route path="profile" element={<CustomerProfile />} />
              </Route>
              
              {/* Admin Routes */}
              <Route path="/admin" element={
                <AdminRoute>
                  <Layout />
                </AdminRoute>
              }>
                <Route index element={<Navigate to="/admin/dashboard" />} />
                <Route path="dashboard" element={<AdminDashboard />} />
                <Route path="sensors" element={<AdminSensors />} />
                <Route path="transactions" element={<AdminTransactions />} />
                <Route path="returns" element={<AdminReturns />} />
                <Route path="ratings" element={<AdminRatings />} />
                <Route path="messages" element={<AdminMessages />} />
                <Route path="reports" element={<AdminReports />} />
                <Route path="users" element={<AdminUsers />} />
              </Route>
              
              {/* Default redirect */}
              <Route path="/" element={<Navigate to="/login" />} />
              <Route path="*" element={<Navigate to="/login" />} />
            </Routes>
          </Router>
          <ToastContainer position="top-right" autoClose={5000} />
        </SocketProvider>
      </AuthProvider>
    </QueryClientProvider>
  );
}

export default App;
